script.text:

function activeJobAccumulationbyNorm(f) {f._controlFocus = f.getItem('ma_vv');}   
function initJobAccumulationbyNorm(f) {
  if (f._action == 'New') {
    f.setItemValue('nam', f._startYear);
    f.getItem('ma_dvcs').value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
  }
}
function setFormJobAccumulationbyNorm(f) {
  f.getItem('lk_no_dk').disabled = f.getItem('lk_co_dk').disabled = f.getItem('lk_no_dk_nt').disabled = f.getItem('lk_co_dk_nt').disabled = (!f._inputYearOpening);
}
